import { Command } from 'commander';
import chalk from 'chalk';
import { spawn } from 'node:child_process';
import { resolve, normalize } from 'node:path';
import { existsSync, writeFileSync, mkdirSync } from 'node:fs';
import { createSqliteStorage } from '@flusk/resources';
import { loadConfig } from '@flusk/forge';
import { createLogger } from '@flusk/logger';

const log = createLogger({ name: 'watch' });

export const watchCommand = new Command('watch')
  .description('Live-watch LLM costs as your script runs (htop for AI spend)')
  .argument('<script>', 'Script to watch')
  .option('-a, --agent <name>', 'Label for multi-agent tracking')
  .action(async (script: string, opts) => {
    const config = await loadConfig();
    const agentLabel = opts.agent || config.agent || process.env.FLUSK_AGENT;
    const storage = createSqliteStorage(config.storage?.path);
    const session = storage.analyzeSessions.create({
      script, durationMs: 0, totalCalls: 0,
      totalCost: 0, modelsUsed: [], startedAt: new Date().toISOString(),
    });

    const scriptPath = resolve(normalize(script));
    const cwd = process.cwd();
    if (!scriptPath.startsWith(cwd) && !scriptPath.startsWith(resolve(process.env.HOME ?? '~'))) {
      console.error(chalk.red(`❌ Path traversal detected: ${scriptPath}`));
      process.exit(1);
    }
    if (!existsSync(scriptPath)) {
      console.error(chalk.red(`❌ Script not found: ${scriptPath}`));
      process.exit(1);
    }

    const child = spawnWithOtel(scriptPath, agentLabel, session.id);
    const { renderWatchApp } = await import('../tui/screens/watch-app.js');
    renderWatchApp({ sessionId: session.id, storage, child });
    log.info({ sessionId: session.id }, 'Watch started');
  });

function getOtelRegisterUrl(): string {
  const startDir = (() => {
    try { const { fileURLToPath } = require('node:url'); return fileURLToPath(new URL('.', import.meta.url)); }
    catch { return process.cwd(); }
  })();
  let dir = startDir;
  for (let i = 0; i < 10; i++) {
    const candidate = resolve(dir, 'packages', 'otel', 'src', 'register.ts');
    if (existsSync(candidate)) return candidate;
    const parent = resolve(dir, '..');
    if (parent === dir) break;
    dir = parent;
  }
  return resolve(process.cwd(), 'packages', 'otel', 'src', 'register.ts');
}

function spawnWithOtel(
  scriptPath: string, agent?: string, sessionId?: string,
) {
  const otelRegister = getOtelRegisterUrl();
  const env: Record<string, string> = {
    ...process.env as Record<string, string>,
    FLUSK_MODE: 'local',
    FLUSK_SQLITE_PATH: resolve(process.env.HOME ?? '~', '.flusk', 'data.db'),
    ...(agent ? { FLUSK_AGENT: agent, FLUSK_AGENT_LABEL: agent } : {}),
    ...(sessionId ? { FLUSK_SESSION_ID: sessionId } : {}),
  };

  const safePath = scriptPath.replace(/\\/g, '/').replace(/'/g, "\\'");
  const safeOtel = otelRegister.replace(/\\/g, '/').replace(/'/g, "\\'");
  const { randomBytes } = require('node:crypto');
  const wrapperId = randomBytes(8).toString('hex');
  const fluskDir = resolve(process.env.HOME ?? '~', '.flusk');
  mkdirSync(fluskDir, { recursive: true });
  const wrapperPath = resolve(fluskDir, `_watch-wrapper-${wrapperId}.mjs`);
  if (existsSync(wrapperPath)) {
    const stats = require('node:fs').lstatSync(wrapperPath);
    if (stats.isSymbolicLink()) {
      throw new Error(`Wrapper path is a symlink — refusing to write: ${wrapperPath}`);
    }
  }
  writeFileSync(wrapperPath, [
    `const { sdk, ready } = await import('${safeOtel}');`,
    `if (ready) await ready;`,
    `await import('${safePath}');`,
    `if (sdk) { await sdk.shutdown(); }`,
  ].join('\n'));

  const otelPkgDir = resolve(otelRegister, '..', '..');
  return spawn('npx', ['tsx', wrapperPath], {
    stdio: 'pipe', env, cwd: otelPkgDir,
  });
}

